	<body>
		<div id="page_0" class="pdf24_ pdf24_02">
			<div class="pdf24_03">
				<img src="data:image/png;base64," alt="" class="pdf24_04" />
			</div>
			<div class="pdf24_view">
				<div class="pdf24_05 pdf24_06">
					<div class="pdf24_01" style="left:22.1342em;top:7.1824em;"><span class="pdf24_07 pdf24_08 pdf24_09" style="word-spacing:-0.0077em;">SURAT KUASA &nbsp;</span></div>
					<div class="pdf24_01" style="left:15.3542em;top:8.5324em;"><span class="pdf24_07 pdf24_08 pdf24_10" style="word-spacing:0.0184em;">No : 010520/HM.10/SKU/50068826/2000/08.2025 &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:10.8124em;"><span class="pdf24_11 pdf24_08 pdf24_12" style="word-spacing:-0.0361em;">PT Semen Indonesia (Persero) Tbk (“Perseroan”)</span><span class="pdf24_13 pdf24_08 pdf24_14" style="word-spacing:-0.0294em;">, sebuah perseroan terbuka yang beralamat di South &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:11.9324em;"><span class="pdf24_13 pdf24_08 pdf24_15" style="word-spacing:0.0649em;">Quarter Tower A, Lantai 19-20, Jl. R.A. Kartini Kav. 8, Jakarta Selatan 12430, DKI Jakarta, Indonesia, &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:13.0524em;"><span class="pdf24_13 pdf24_08 pdf24_16" style="word-spacing:0.0083em;">yang dalam hal ini diwakili oleh </span><span class="pdf24_07 pdf24_08 pdf24_14" style="word-spacing:0.0139em;">Group Head of Operational Human Capital </span><span class="pdf24_13 pdf24_08 pdf24_17" style="word-spacing:0.0086em;">yang saat ini dijabat oleh &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:14.1724em;"><span class="pdf24_07 pdf24_08 pdf24_17">Febrianadita &nbsp;</span></div>
					<div class="pdf24_01" style="left:12.1301em;top:14.1724em;"><span class="pdf24_07 pdf24_08 pdf24_18">Kusuma &nbsp;</span></div>
					<div class="pdf24_01" style="left:16.4942em;top:14.1724em;"><span class="pdf24_13 pdf24_08 pdf24_19">berdasarkan &nbsp;</span></div>
					<div class="pdf24_01" style="left:22.4438em;top:14.1724em;"><span class="pdf24_13 pdf24_08 pdf24_19">Surat &nbsp;</span></div>
					<div class="pdf24_01" style="left:25.7227em;top:14.1724em;"><span class="pdf24_13 pdf24_08 pdf24_20">Kuasa &nbsp;</span></div>
					<div class="pdf24_01" style="left:29.2316em;top:14.1724em;"><span class="pdf24_13 pdf24_08 pdf24_19">dengan &nbsp;</span></div>
					<div class="pdf24_01" style="left:33.321em;top:14.1724em;"><span class="pdf24_13 pdf24_08 pdf24_21">Hak &nbsp;</span></div>
					<div class="pdf24_01" style="left:36.0598em;top:14.1724em;"><span class="pdf24_13 pdf24_08 pdf24_22">Substitusi &nbsp;</span></div>
					<div class="pdf24_01" style="left:40.9892em;top:14.1724em;"><span class="pdf24_13 pdf24_08 pdf24_23">Nomor &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:15.2924em;"><span class="pdf24_13 pdf24_08 pdf24_24" style="word-spacing:0.2628em;">015801/SM/SKU/50067345/2000/08.2025 tertanggal 1 Agustus 2025 (untuk selanjutnya disebut &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:16.4124em;"><span class="pdf24_13 pdf24_08 pdf24_25" style="word-spacing:0.0011em;">sebagai </span><span class="pdf24_11 pdf24_08 pdf24_26" style="word-spacing:0.0103em;">“Pemberi Kuasa” </span><span class="pdf24_13 pdf24_08 pdf24_27" style="word-spacing:0.0081em;">atau </span><span class="pdf24_11 pdf24_08 pdf24_24">“Perseroan”</span><span class="pdf24_13 pdf24_08 pdf24_28">), &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:18.6924em;"><span class="pdf24_13 pdf24_08 pdf24_15" style="word-spacing:0.124em;">dengan ini menerangkan bahwa melalui surat kuasa ini (untuk selanjutnya disebut sebagai </span><span class="pdf24_11 pdf24_08 pdf24_26">“Surat &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:19.8124em;"><span class="pdf24_11 pdf24_08 pdf24_29">Kuasa”</span><span class="pdf24_13 pdf24_08 pdf24_14" style="word-spacing:0.0303em;">) Pemberi Kuasa memberikan kuasa dan kewenangan kepada para pekerja Perseroan dengan &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:20.9349em;"><span class="pdf24_13 pdf24_08 pdf24_15" style="word-spacing:0.0001em;">nama (dilengkapi jabatan yang dijabat saat tanggal Surat Kuasa ini) sebagai berikut &nbsp;</span></div>
					<div class="pdf24_01" style="left:7.532em;top:23.2649em;"><span class="pdf24_13 pdf24_08 pdf24_30">No. &nbsp;</span></div>
					<div class="pdf24_01" style="left:7.972em;top:24.4249em;"><span class="pdf24_13 pdf24_08 pdf24_31">1. &nbsp;</span></div>
					<div class="pdf24_01" style="left:14.7342em;top:23.2649em;"><span class="pdf24_13 pdf24_08 pdf24_32">Nama &nbsp;</span></div>
					<div class="pdf24_01" style="left:10.8017em;top:24.4249em;"><span class="pdf24_13 pdf24_08 pdf24_24" style="word-spacing:0.004em;">Sigit Wahono &nbsp;</span></div>
					<div class="pdf24_01" style="left:31.0058em;top:23.2649em;"><span class="pdf24_13 pdf24_08 pdf24_33">Jabatan &nbsp;</span></div>
					<div class="pdf24_01" style="left:21.7842em;top:24.4249em;"><span class="pdf24_13 pdf24_08 pdf24_34" style="word-spacing:-0.002em;">GM of Corporate Learning &amp; Development &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:25.8049em;"><span class="pdf24_13 pdf24_08 pdf24_15" style="word-spacing:0.0022em;">(Untuk selanjutnya disebut sebagai </span><span class="pdf24_11 pdf24_08 pdf24_35">“</span><span class="pdf24_07 pdf24_08 pdf24_36" style="word-spacing:0.0046em;">Penerima Kuasa</span><span class="pdf24_11 pdf24_08 pdf24_37">”</span><span class="pdf24_13 pdf24_08 pdf24_37">) &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:28.0849em;"><span class="pdf24_07 pdf24_08 pdf24_33" style="word-spacing:0.0022em;">----------------------------------------------------------- K HU S U S ----------------------------------------------------------- &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:30.3749em;"><span class="pdf24_13 pdf24_08 pdf24_19" style="word-spacing:0.0494em;">untuk bertindak dan atas nama Pemberi Kuasa membuat dan/atau menandatangani surat dan/atau &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:31.4949em;"><span class="pdf24_13 pdf24_08 pdf24_15" style="word-spacing:-0.0255em;">dokumen yang termasuk kewenangan operasional Pemberi Kuasa di Departemen </span><span class="pdf24_07 pdf24_08 pdf24_34" style="word-spacing:-0.0311em;">Corporate Learning &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:32.6149em;"><span class="pdf24_07 pdf24_08 pdf24_18" style="word-spacing:0.0072em;">&amp; Development</span><span class="pdf24_13 pdf24_08 pdf24_19" style="word-spacing:0.0012em;">, dimana secara rinci meliputi: &nbsp;</span></div>
					<div class="pdf24_01" style="left:7.502em;top:34.8965em;"><span class="pdf24_13 pdf24_08 pdf24_32" style="word-spacing:0.6408em;">1. Untuk</span><span class="pdf24_13 pdf24_08 pdf24_20" style="word-spacing:0.2844em;">&nbsp;</span><span class="pdf24_13 pdf24_08 pdf24_22" style="word-spacing:0.275em;">dan atas nama Pemberi Kuasa untuk membuat dan menandatangani dokumen- &nbsp;</span></div>
					<div class="pdf24_01" style="left:9.0017em;top:36.0165em;"><span class="pdf24_13 pdf24_08 pdf24_36" style="word-spacing:0.1431em;">dokumen terkait kerja sama Perseroan dengan perguruan tinggi dan/atau lembaga ilmiah &nbsp;</span></div>
					<div class="pdf24_01" style="left:9.0017em;top:37.1365em;"><span class="pdf24_13 pdf24_08 pdf24_16" style="word-spacing:-0.0036em;">lainnya, yang dikelola oleh </span><span class="pdf24_07 pdf24_08 pdf24_33" style="word-spacing:0.0009em;">Group Head of Operational Human Capital</span><span class="pdf24_13 pdf24_08 pdf24_33" style="word-spacing:0.0009em;">; &nbsp;</span></div>
					<div class="pdf24_01" style="left:7.502em;top:38.2565em;"><span class="pdf24_13 pdf24_08 pdf24_22" style="word-spacing:0.643em;">2. Dalam</span><span class="pdf24_13 pdf24_08 pdf24_20" style="word-spacing:0.3432em;">&nbsp;</span><span class="pdf24_13 pdf24_08 pdf24_16" style="word-spacing:0.3346em;">melaksanakan tindakan tersebut di atas, Penerima Kuasa diberikan kuasa dan &nbsp;</span></div>
					<div class="pdf24_01" style="left:9.0017em;top:39.3765em;"><span class="pdf24_13 pdf24_08 pdf24_34" style="word-spacing:0.0018em;">wewenang untuk: &nbsp;</span></div>
					<div class="pdf24_01" style="left:10.5017em;top:40.4965em;"><span class="pdf24_13 pdf24_08 pdf24_33" style="word-spacing:0.6762em;">a. Membuat</span><span class="pdf24_13 pdf24_08 pdf24_20" style="word-spacing:0.0032em;">&nbsp;</span><span class="pdf24_13 pdf24_08 pdf24_33" style="word-spacing:-0.0052em;">dan menandatangani dokumen-dokumen terkait; &nbsp;</span></div>
					<div class="pdf24_01" style="left:10.5017em;top:41.6165em;"><span class="pdf24_13 pdf24_08 pdf24_38" style="word-spacing:0.6322em;">b. Menerima</span><span class="pdf24_13 pdf24_08 pdf24_20" style="word-spacing:0.0009em;">&nbsp;</span><span class="pdf24_13 pdf24_08 pdf24_34" style="word-spacing:-0.0036em;">jawaban, tanggapan dan/atau dokumen-dokumen terkait; &nbsp;</span></div>
					<div class="pdf24_01" style="left:10.5017em;top:42.7365em;"><span class="pdf24_13 pdf24_08 pdf24_16" style="word-spacing:0.7299em;">c. Menghadap</span><span class="pdf24_13 pdf24_08 pdf24_20" style="word-spacing:0.2365em;">&nbsp;</span><span class="pdf24_13 pdf24_08 pdf24_19" style="word-spacing:0.2395em;">kepada pihak-pihak yang berkepentingan atau instansi yang terkait, &nbsp;</span></div>
					<div class="pdf24_01" style="left:12.0017em;top:43.8465em;"><span class="pdf24_13 pdf24_08 pdf24_18" style="word-spacing:-0.0291em;">untuk memberikan keterangan, dan juga menandatangani segala dokumen, bilamana &nbsp;</span></div>
					<div class="pdf24_01" style="left:12.0017em;top:44.9665em;"><span class="pdf24_13 pdf24_08 pdf24_19" style="word-spacing:0.3867em;">dianggap perlu oleh Penerima Kuasa untuk kepentingan Pemberi Kuasa, dan &nbsp;</span></div>
					<div class="pdf24_01" style="left:12.0017em;top:46.0865em;"><span class="pdf24_13 pdf24_08 pdf24_34" style="word-spacing:0.2215em;">selanjutnya melakukan setiap dan segala tindakan-tindakan lain yang perlu atau &nbsp;</span></div>
					<div class="pdf24_01" style="left:12.0017em;top:47.2065em;"><span class="pdf24_13 pdf24_08 pdf24_22" style="word-spacing:-0.0028em;">dianggap perlu oleh Penerima Kuasa sesuai dengan peraturan atau hukum; &nbsp;</span></div>
					<div class="pdf24_01" style="left:7.502em;top:49.499em;"><span class="pdf24_13 pdf24_08 pdf24_39" style="word-spacing:0.6417em;">3. Melakukan</span><span class="pdf24_13 pdf24_08 pdf24_20" style="word-spacing:0.097em;">&nbsp;</span><span class="pdf24_13 pdf24_08 pdf24_14" style="word-spacing:0.0936em;">hal-hal lainnya yang menurut Penerima Kuasa dianggap perlu, penting berguna &nbsp;</span></div>
					<div class="pdf24_01" style="left:9.0017em;top:50.619em;"><span class="pdf24_13 pdf24_08 pdf24_14" style="word-spacing:0.0015em;">dan baik bagi Pemberi Kuasa dengan tetap memperhatikan peraturan perundang-undangan. &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:52.899em;"><span class="pdf24_13 pdf24_08 pdf24_22" style="word-spacing:0.0664em;">Surat Kuasa ini berlaku pada tanggal penandatanganannya, dan akan berakhir pada saat (i) pejabat &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:54.019em;"><span class="pdf24_13 pdf24_08 pdf24_38" style="word-spacing:0.1416em;">yang bersangkutan di atas tidak lagi menjabat atau nama jabatan berubah, atau (ii) diakhiri atau &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:55.139em;"><span class="pdf24_13 pdf24_08 pdf24_16" style="word-spacing:-0.0054em;">dicabut secara tertulis oleh Pemberi Kuasa, peristiwa mana yang terjadi terlebih dahulu. &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:57.429em;"><span class="pdf24_13 pdf24_08 pdf24_33" style="word-spacing:0.1086em;">Demikian Surat Kuasa ini dibuat untuk dapat dipergunakan sesuai peraturan perundang-undangan &nbsp;</span></div>
					<div class="pdf24_01" style="left:6.002em;top:58.549em;"><span class="pdf24_13 pdf24_08 pdf24_40" style="word-spacing:-0.003em;">yang berlaku. &nbsp;</span></div>
			</div>
		</div>
		<div id="page_1" class="pdf24_ pdf24_02">
			<div class="pdf24_03">
				<img src="data:image/png;base64," alt="" class="pdf24_42" />
			</div>
			<div class="pdf24_view">
